#include 
#include 
#include 
#include "config.h"
#include "buffer.h"
#include "mqtt_client.h"

DHT         dht(DHT_PIN, DHT_TYPE);
CircularBuffer buffer;
MqttClient  mqtt;

unsigned long lastReadMs    = 0;
unsigned long lastReconnect = 0;

// ── WiFi ──────────────────────────────────────────────────────────────────────

void connectWiFi() {
    if (WiFi.status() == WL_CONNECTED) return;
    Serial.printf("[WiFi] Connecting to %s", WIFI_SSID);
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
    unsigned long start = millis();
    while (WiFi.status() != WL_CONNECTED && millis() - start < 10000) {
        delay(500);
        Serial.print(".");
    }
    Serial.println(WiFi.status() == WL_CONNECTED ? " Connected!" : " Failed.");
}

// ── Flush local buffer to ThingsBoard ────────────────────────────────────────

void flushBuffer() {
    if (buffer.isEmpty()) return;
    Serial.printf("[Buffer] Flushing %d buffered entries...\n", buffer.count());
    SensorPayload p;
    while (buffer.pop(p)) {
        if (!mqtt.publish(p)) {
            // Re-push on failure and stop flushing
            buffer.push(p);
            Serial.println("[Buffer] Flush interrupted, will retry.");
            break;
        }
    }
}

// ── Read sensor ───────────────────────────────────────────────────────────────

SensorPayload readSensor() {
    SensorPayload p;
    p.humidity    = dht.readHumidity();
    p.temperature = dht.readTemperature();
    p.timestamp   = millis();
    return p;
}

// ─────────────────────────────────────────────────────────────────────────────

void setup() {
    Serial.begin(115200);
    dht.begin();
    mqtt.begin();
    connectWiFi();
}

void loop() {
    // Keep MQTT alive
    mqtt.loop();

    // Reconnect WiFi + MQTT if needed
    if (millis() - lastReconnect >= RECONNECT_DELAY_MS) {
        lastReconnect = millis(); // Update before attempting to prevent rapid retries
        if (WiFi.status() != WL_CONNECTED) connectWiFi();
        if (WiFi.status() == WL_CONNECTED && !mqtt.isConnected()) {
            if (mqtt.connect()) flushBuffer();
        }
    }

    // Read sensor on interval
    if (millis() - lastReadMs < READ_INTERVAL_MS) return;
    lastReadMs = millis();

    SensorPayload p = readSensor();

    if (isnan(p.temperature) || isnan(p.humidity)) {
        Serial.println("[Sensor] Read failed.");
        return;
    }

    Serial.printf("[Sensor] Temp: %.1f°C | Hum: %.1f%%\n", p.temperature, p.humidity);

    if (mqtt.isConnected()) {
        if (!mqtt.publish(p)) buffer.push(p);
    } else {
        Serial.println("[Buffer] Offline — storing locally.");
        buffer.push(p);
        Serial.printf("[Buffer] %d/%d entries stored.\n", buffer.count(), MAX_BUFFER_SIZE);
    }
}



#pragma once
#include 
#include 
#include 
#include 
#include "config.h"
#include "buffer.h"

class MqttClient {
public:
    MqttClient() : _wifiClient(), _client(_wifiClient) {}

    void begin() {
        _wifiClient.setCACert(TB_CA_CERT);
        _client.setServer(TB_HOST, TB_PORT);
    }

    bool isConnected() {
        return _client.connected();
    }

    void loop() {
        _client.loop();
    }

    bool connect() {
        if (_client.connected()) return true;
        Serial.print("[MQTT] Connecting to ThingsBoard (TLS)... ");
        bool ok = _client.connect("ESP32_SISF", TB_ACCESS_TOKEN, nullptr);
        Serial.println(ok ? "OK" : "FAILED");
        return ok;
    }

    bool publish(const SensorPayload& p) {
        if (!_client.connected()) return false;

        JsonDocument doc;
        doc["temperature"] = p.temperature;
        doc["humidity"]    = p.humidity;

        char buf[128];
        serializeJson(doc, buf);

        bool ok = _client.publish(TB_TOPIC, buf, false);
        if (ok) Serial.printf("[MQTT] Published: %s\n", buf);
        else    Serial.println("[MQTT] Publish failed");
        return ok;
    }

private:
    WiFiClientSecure _wifiClient;
    PubSubClient     _client;
};









